// src/pages/supervisor/index.jsx
import { useState, useEffect, useCallback } from "react";
import { taskAPI, userAPI, reportAPI, projectAPI, authAPI } from "../../utils/api";
import { StatusBadge, Avatar, Toast } from "../../components/shared/index.jsx";
import TaskModal from "../../components/shared/TaskModal.jsx";
import SubTaskList from "../../components/shared/SubTaskList.jsx";
import { WeeklyHoursBar } from "../../components/shared/WeeklyHoursCard.jsx";
import { computeStats, formatMinutes, statusSelectClass } from "../../utils/helpers";
import { useAuth } from "../../hooks/useAuth";

// ── Leave Day Badge ───────────────────────────────────────────────────────────
function LeaveBadge({ reason }) {
  return (
    <span style={{
      display:"inline-flex", alignItems:"center", gap:5,
      padding:"3px 10px", borderRadius:99, fontSize:11, fontWeight:700,
      background:"#fef3c7", color:"#92400e", border:"1px solid #fde68a",
    }}>
      🏖️ Leave Day{reason ? ` — ${reason}` : ""}
    </span>
  );
}

// ── SUPERVISOR DASHBOARD ──────────────────────────────────────────────────────
export function SupervisorDashboard() {
  const { user, isSenior } = useAuth();
  const [report,    setReport]    = useState([]);
  const [myTasks,   setMyTasks]   = useState([]);
  const [allTasks,  setAllTasks]  = useState([]);
  const [loading,   setLoading]   = useState(true);

  useEffect(() => {
    const myId = String(user._id || user.id || "");
    const calls = [
      taskAPI.getAll(),  // fetch all, then split client-side (reliable)
    ];
    if (isSenior) calls.push(reportAPI.interns());

    Promise.all(calls)
      .then(([all, r]) => {
        const allList = all.tasks || [];
        // Own tasks = assigned to self
        setMyTasks(allList.filter(t => String(t.assignedTo?._id || t.assignedTo) === myId));
        // Others tasks = NOT assigned to self
        setAllTasks(allList.filter(t => String(t.assignedTo?._id || t.assignedTo) !== myId));
        if (r) setReport(r.report || []);
        setLoading(false);
      })
      .catch(() => setLoading(false));
  }, [isSenior, user._id, user.id]);

  // Stats from OWN tasks only
  const myNonLeave = myTasks.filter(t => !t.isLeave);
  const { total: myTotal, done: myDone, inProgress: myInProgress } = computeStats(myNonLeave);
  const myTotalMins = myNonLeave.reduce((s, t) => s + (parseInt(t.totalMinutes)||0), 0);
  const myLeaveDays = myTasks.filter(t => t.isLeave).length;

  // Recent activity = tasks assigned to others
  const recentActivity = [...allTasks].sort((a,b) => new Date(b.date)-new Date(a.date)).slice(0,10);

  if (loading) return <div style={{ padding:60, textAlign:"center" }}><div className="spinner"/></div>;

  return (
    <div className="animate-fadeUp">
      {/* ── My task stats ── */}
      <div className="grid-4 mb-24">
        {[
          ["👥","Active Interns",  isSenior ? report.length : "—",  "stat-green", "neutral"],
          ["📋","My Total Tasks",  myTotal,                          "stat-blue",  "neutral"],
          ["✅","My Completed",    myDone,                           "stat-gold",  "up"],
          ["🏖️","My Leave Days",  myLeaveDays,                      "stat-red",   "neutral"],
        ].map(([icon,label,val,cls,chg]) => (
          <div key={label} className={`stat-card ${cls}`}>
            <div className="stat-icon">{icon}</div>
            <div className="stat-value">{val}</div>
            <div className="stat-label">{label}</div>
            <div className={`stat-change ${chg}`}>
              {chg === "up"
                ? `↑ ${myTotal ? Math.round(myDone/myTotal*100) : 0}% rate`
                : "All time"}
            </div>
          </div>
        ))}
      </div>

      <div className="grid-2 mb-24">
        {/* Intern weekly hours — senior only */}
        {isSenior && (
          <div className="card">
            <div className="card-header"><div className="card-title">👥 Intern Weekly Hours</div></div>
            <div className="card-body">
              {report.map(intern => (
                <div key={intern._id} style={{ marginBottom:20, paddingBottom:20, borderBottom:"1px solid #f1f5f9" }}>
                  <div className="flex items-center gap-10 mb-8">
                    <Avatar initials={intern.avatar} color={intern.avatarColor} size="sm"/>
                    <div style={{ flex:1 }}>
                      <div style={{ fontSize:13, fontWeight:600 }}>{intern.name.split(" ")[0]}</div>
                      <div style={{ fontSize:11, color:"var(--gray-400)" }}>{intern.stats.total} tasks · {formatMinutes(intern.stats.totalMins)}</div>
                    </div>
                    <span style={{ fontFamily:"Syne,sans-serif", fontWeight:700, fontSize:13, color:intern.stats.pct>70?"var(--green-500)":"var(--orange)" }}>{intern.stats.pct}% done</span>
                  </div>
                  <WeeklyHoursBar weekMins={intern.stats.weekMins||0} compact/>
                </div>
              ))}
              {report.length===0 && <p style={{ color:"var(--gray-400)", fontSize:13 }}>No intern data yet.</p>}
            </div>
          </div>
        )}

        {/* My overview */}
        <div>
          <div className="week-summary mb-16">
            <h3>📊 My Overview</h3>
            {[
              ["My Hours Logged",   formatMinutes(myTotalMins),                                 "good"],
              ["My In Progress",    myInProgress,                                               "warn"],
              ["My Completion",     `${myTotal ? Math.round(myDone/myTotal*100) : 0}%`,        "good"],
            ].map(([l,v,c]) => (
              <div key={l} className="week-stat">
                <span className="week-stat-label">{l}</span>
                <span className={`week-stat-val ${c}`}>{v}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Recent activity = tasks assigned to others */}
      <div className="card">
        <div className="card-header">
          <div className="card-title">🕐 Recent Assigned Activity</div>
          <span style={{ fontSize:11, color:"var(--gray-400)" }}>Tasks assigned to interns / others</span>
        </div>
        <div className="table-wrap">
          {recentActivity.length === 0
            ? <div className="empty-state" style={{ padding:32 }}><div className="empty-icon">📭</div><h3>No tasks assigned yet</h3></div>
            : (
              <table>
                <thead><tr><th>Date</th><th>Assigned To</th><th>Project</th><th>Task</th><th>Status</th><th>Mins</th></tr></thead>
                <tbody>
                  {recentActivity.map(t => (
                    <tr key={t._id||t.id} style={t.isLeave ? { background:"#fffbeb" } : {}}>
                      <td className="text-sm text-gray">{t.date}</td>
                      <td>{t.assignedTo && <div className="flex items-center gap-8"><Avatar initials={t.assignedTo.avatar} color={t.assignedTo.avatarColor} size="sm"/><span className="text-sm">{(t.assignedTo.name||"").split(" ")[0]}</span></div>}</td>
                      <td>{t.isLeave ? "—" : <span className="tag">{t.project}</span>}</td>
                      <td className="text-sm" style={{ maxWidth:200 }}>
                        {t.isLeave ? <LeaveBadge reason={t.leaveReason}/> : t.task}
                      </td>
                      <td>{t.isLeave ? "—" : <StatusBadge status={t.status}/>}</td>
                      <td className="text-sm text-bold">{t.isLeave ? "—" : t.totalMinutes}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )
          }
        </div>
      </div>
    </div>
  );
}

// ── MY TASKS PAGE (supervisors) ───────────────────────────────────────────────
export function MyTasksPageSupervisor() {
  const { user }    = useAuth();
  const [tasks,     setTasks]     = useState([]);
  const [loading,   setLoading]   = useState(true);
  const [saving,    setSaving]    = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [editTask,  setEditTask]  = useState(null);
  const [toast,     setToast]     = useState(null);
  const [status,    setStatus]    = useState("All");
  const [search,    setSearch]    = useState("");

  const load = useCallback(() => {
    setLoading(true);
    taskAPI.getAll({ status:status!=="All"?status:undefined, search:search||undefined, internId: user._id })
      .then(d => {
        // Filter to only tasks assigned to self
        setTasks((d.tasks||[]).filter(t => (t.assignedTo?._id||t.assignedTo) === user._id));
        setLoading(false);
      })
      .catch(() => setLoading(false));
  }, [status, search, user._id]);

  useEffect(() => { load(); }, [load]);

  const handleSave = async (form) => {
    setSaving(true);
    try {
      const taskForm = { ...form, assignedTo: user._id };
      if (editTask) {
        const d = await taskAPI.update(editTask._id||editTask.id, taskForm);
        setTasks(ts => ts.map(t => (t._id||t.id)===(editTask._id||editTask.id) ? d.task : t));
        setToast({ msg:"Task updated!", type:"success" });
      } else {
        const d = await taskAPI.create(taskForm);
        setTasks(ts => [d.task, ...ts]);
        setToast({ msg: form.isLeave ? "Leave day marked!" : "Task created!", type:"success" });
      }
      setShowModal(false); setEditTask(null);
    } catch(e) { setToast({ msg:e.message, type:"error" }); }
    setSaving(false);
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this task?")) return;
    try {
      await taskAPI.delete(id);
      setTasks(ts => ts.filter(t => (t._id||t.id)!==id));
      setToast({ msg:"Deleted.", type:"success" });
    } catch(e) { setToast({ msg:e.message, type:"error" }); }
  };

  const handleTaskUpdated = (updated) => {
    setTasks(ts => ts.map(t => (t._id||t.id)===(updated._id||updated.id) ? updated : t));
  };

  return (
    <div className="animate-fadeUp">
      {toast && <Toast message={toast.msg} type={toast.type} onClose={() => setToast(null)}/>}
      {showModal && (
        <TaskModal
          task={editTask}
          currentUser={{ ...user, role:"intern" }} // no intern picker — task is for self
          onClose={() => { setShowModal(false); setEditTask(null); }}
          onSave={handleSave}
          loading={saving}
        />
      )}
      <div className="card">
        <div className="card-header">
          <div className="card-title">✅ My Tasks</div>
          <button className="btn btn-primary" onClick={() => { setEditTask(null); setShowModal(true); }}>+ New Task</button>
        </div>
        <div style={{ padding:"14px 24px", borderBottom:"1px solid var(--gray-100)" }}>
          <div className="filters">
            <div className="search-wrap"><span className="search-icon">🔍</span><input className="search-input" placeholder="Search…" value={search} onChange={e=>setSearch(e.target.value)}/></div>
            <select className="filter-select" value={status} onChange={e=>setStatus(e.target.value)}>
              <option value="All">All Status</option>
              {["To Do","In Progress","Done","Hold"].map(s=><option key={s}>{s}</option>)}
            </select>
            <span className="text-sm text-gray" style={{ marginLeft:"auto" }}>{tasks.length} records</span>
          </div>
        </div>
        <div className="table-wrap">
          {loading
            ? <div style={{ padding:40, textAlign:"center" }}><div className="spinner"/></div>
            : tasks.length===0
              ? <div className="empty-state"><div className="empty-icon">📭</div><h3>No tasks yet</h3><p>Create your first task above.</p></div>
              : (
                <table>
                  <thead><tr><th>Date</th><th>Project</th><th>Task / Sub-tasks</th><th>Status</th><th>Estimate</th><th>Mins</th><th>Doc</th><th>Actions</th></tr></thead>
                  <tbody>
                    {tasks.map(t => (
                      <tr key={t._id||t.id} style={t.isLeave ? { background:"#fffbeb" } : {}}>
                        <td className="text-sm text-gray">{t.date}</td>
                        <td>{t.isLeave ? "—" : <span className="tag">{t.project}</span>}</td>
                        <td className="text-sm" style={{ maxWidth:220 }}>
                          {t.isLeave
                            ? <LeaveBadge reason={t.leaveReason}/>
                            : <><div style={{ marginBottom:4 }}>{t.task}</div><SubTaskList task={t} currentUser={user} onTaskUpdated={handleTaskUpdated}/></>
                          }
                        </td>
                        <td>
                          {t.isLeave ? "—" : (
                            <select className={`status-select ${statusSelectClass(t.status)}`} value={t.status}
                              onChange={async e => { const d=await taskAPI.updateStatus(t._id||t.id,e.target.value); setTasks(ts=>ts.map(x=>(x._id||x.id)===(t._id||t.id)?d.task:x)); }}>
                              {["To Do","In Progress","Done","Hold"].map(s=><option key={s}>{s}</option>)}
                            </select>
                          )}
                        </td>
                        <td className="text-sm">{t.isLeave ? "—" : t.estimateTime}</td>
                        <td className="text-sm text-bold">{t.isLeave ? "—" : t.totalMinutes}</td>
                        <td>{t.workDoc ? <a href={t.workDoc} target="_blank" rel="noreferrer" style={{ color:"var(--green-600)",fontSize:17 }}>🔗</a> : "–"}</td>
                        <td><div className="flex gap-6">
                          {!t.isLeave && <button className="btn btn-secondary btn-sm btn-icon" onClick={()=>{setEditTask(t);setShowModal(true);}}>✏️</button>}
                          <button className="btn btn-danger btn-sm btn-icon" onClick={()=>handleDelete(t._id||t.id)}>🗑</button>
                        </div></td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              )
          }
        </div>
      </div>
    </div>
  );
}

// ── ALL TASKS PAGE — tasks assigned to others ONLY (not self) ─────────────────
export function AllTasksPage() {
  const { user, isSenior }  = useAuth();
  const [tasks,       setTasks]       = useState([]);
  const [loading,     setLoading]     = useState(true);
  const [saving,      setSaving]      = useState(false);
  const [showModal,   setShowModal]   = useState(false);
  const [editTask,    setEditTask]    = useState(null);
  const [toast,       setToast]       = useState(null);
  const [status,      setStatus]      = useState("All");
  const [internId,    setInternId]    = useState("All");
  const [filterUsers, setFilterUsers] = useState([]);
  const [search,      setSearch]      = useState("");

  useEffect(() => {
    if (isSenior) {
      Promise.all([userAPI.getAll("intern"), userAPI.getAll("supervisor")])
        .then(([i, s]) => setFilterUsers([...(i.users||[]), ...(s.users||[])]))
        .catch(() => {});
    } else {
      userAPI.getAll("intern").then(d => setFilterUsers(d.users||[])).catch(()=>{});
    }
  }, [isSenior]);

  const load = useCallback(() => {
    setLoading(true);
    const myId = String(user._id || user.id || "");
    taskAPI.getAll({
      status:   status   !== "All" ? status   : undefined,
      internId: internId !== "All" ? internId : undefined,
      search:   search   || undefined,
    })
      .then(d => {
        // Exclude tasks assigned to self — All Tasks shows others only
        const others = (d.tasks||[]).filter(t =>
          String(t.assignedTo?._id || t.assignedTo) !== myId
        );
        setTasks(others);
        setLoading(false);
      })
      .catch(() => setLoading(false));
  }, [status, internId, search, user._id, user.id]);

  useEffect(() => { load(); }, [load]);

  const handleSave = async (form) => {
    setSaving(true);
    try {
      if (editTask) {
        const d = await taskAPI.update(editTask._id||editTask.id, form);
        setTasks(ts=>ts.map(t=>(t._id||t.id)===(editTask._id||editTask.id)?d.task:t));
        setToast({ msg:"Task updated!", type:"success" });
      } else {
        const d = await taskAPI.create(form);
        // Only add to list if it's NOT assigned to self
        if ((d.task.assignedTo?._id||d.task.assignedTo) !== user._id) {
          setTasks(ts=>[d.task,...ts]);
        }
        setToast({ msg: form.isLeave ? "Leave day marked!" : "Task assigned!", type:"success" });
      }
      setShowModal(false); setEditTask(null);
    } catch(e) { setToast({ msg:e.message, type:"error" }); }
    setSaving(false);
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this task?")) return;
    try {
      await taskAPI.delete(id);
      setTasks(ts=>ts.filter(t=>(t._id||t.id)!==id));
      setToast({ msg:"Deleted.", type:"success" });
    } catch(e) { setToast({ msg:e.message, type:"error" }); }
  };

  const handleCheck = async (id) => {
    try {
      const d = await taskAPI.toggleCheck(id);
      setTasks(ts=>ts.map(t=>(t._id||t.id)===id?d.task:t));
    } catch(e) { setToast({ msg:e.message, type:"error" }); }
  };

  const handleTaskUpdated = (updated) => {
    setTasks(ts=>ts.map(t=>(t._id||t.id)===(updated._id||updated.id)?updated:t));
  };

  // Filter list: exclude self from member filter dropdown
  const filterableUsers = filterUsers.filter(u => u._id !== user._id);

  return (
    <div className="animate-fadeUp">
      {toast && <Toast message={toast.msg} type={toast.type} onClose={() => setToast(null)}/>}
      {showModal && <TaskModal task={editTask} currentUser={user} onClose={() => { setShowModal(false); setEditTask(null); }} onSave={handleSave} loading={saving}/>}

      <div className="card">
        <div className="card-header">
          <div className="card-title">📋 All Tasks</div>
          <button className="btn btn-primary" onClick={()=>{setEditTask(null);setShowModal(true);}}>+ Assign Task</button>
        </div>
        <div style={{ padding:"14px 24px", borderBottom:"1px solid var(--gray-100)" }}>
          <div className="filters">
            <div className="search-wrap">
              <span className="search-icon">🔍</span>
              <input className="search-input" placeholder="Search…" value={search} onChange={e=>setSearch(e.target.value)}/>
            </div>
            <select className="filter-select" value={status} onChange={e=>setStatus(e.target.value)}>
              <option value="All">All Status</option>
              {["To Do","In Progress","Done","Hold"].map(s=><option key={s}>{s}</option>)}
            </select>
            <select className="filter-select" value={internId} onChange={e=>setInternId(e.target.value)}>
              <option value="All">All Members</option>
              {filterableUsers.filter(u=>u.role==="intern").map(i=>(
                <option key={i._id} value={i._id}>{i.name.split(" ")[0]} (Intern)</option>
              ))}
              {isSenior && filterableUsers.filter(u=>u.role==="supervisor").map(s=>(
                <option key={s._id} value={s._id}>
                  {s.name.replace("Mr. ","").replace("Miss. ","")} ({s.supervisorLevel==="senior"?"Senior Sup":"Supervisor"})
                </option>
              ))}
            </select>
            <span className="text-sm text-gray" style={{ marginLeft:"auto" }}>{tasks.length} records</span>
          </div>
        </div>

        <div className="table-wrap">
          {loading
            ? <div style={{ padding:40, textAlign:"center" }}><div className="spinner"/></div>
            : tasks.length===0
              ? <div className="empty-state"><div className="empty-icon">📭</div><h3>No tasks found</h3><p>Tasks you assign to others will appear here.</p></div>
              : (
                <table>
                  <thead>
                    <tr><th>Date</th><th>Assigned To</th><th>Project</th><th>Task / Sub-tasks</th><th>Status</th><th>Estimate</th><th>Doc</th><th>Checked By</th><th>Actions</th></tr>
                  </thead>
                  <tbody>
                    {tasks.map(t => (
                      <tr key={t._id||t.id} style={t.isLeave ? { background:"#fffbeb" } : {}}>
                        <td className="text-sm text-gray">{t.date}</td>
                        <td>
                          {t.assignedTo && (
                            <div className="flex items-center gap-8">
                              <Avatar initials={t.assignedTo.avatar} color={t.assignedTo.avatarColor} size="sm"/>
                              <span className="text-sm">{(t.assignedTo.name||"").split(" ")[0]}</span>
                            </div>
                          )}
                        </td>
                        <td>{t.isLeave ? "—" : <span className="tag">{t.project}</span>}</td>
                        <td className="text-sm" style={{ maxWidth:200 }}>
                          {t.isLeave
                            ? <LeaveBadge reason={t.leaveReason}/>
                            : <><div style={{ marginBottom:4 }}>{t.task}</div><SubTaskList task={t} currentUser={user} onTaskUpdated={handleTaskUpdated}/></>
                          }
                        </td>
                        <td>{t.isLeave ? "—" : <StatusBadge status={t.status}/>}</td>
                        <td className="text-sm">{t.isLeave ? "—" : t.estimateTime}</td>
                        <td className="text-sm text-bold">{t.isLeave ? "—" : t.totalMinutes}</td>
                        <td>{t.workDoc ? <a href={t.workDoc} target="_blank" rel="noreferrer" style={{ color:"var(--green-600)",fontSize:17 }}>🔗</a> : "–"}</td>
                        <td>
                          {t.isLeave ? "—" : (
                            <button
                              onClick={()=>handleCheck(t._id||t.id)}
                              style={{
                                background: (t.adminChecked||[]).includes(user.username) ? "#dcfce7" : "#f3f4f6",
                                border:"none", borderRadius:6, padding:"4px 10px", fontSize:11, fontWeight:700,
                                cursor:"pointer", fontFamily:"inherit",
                                color: (t.adminChecked||[]).includes(user.username) ? "#166534" : "#6b7280",
                              }}
                            >
                              {(t.adminChecked||[]).includes(user.username) ? "✓ Checked" : "Mark"}
                            </button>
                          )}
                        </td>
                        <td>
                          <div className="flex gap-6">
                            {!t.isLeave && <button className="btn btn-secondary btn-sm btn-icon" onClick={()=>{setEditTask(t);setShowModal(true);}}>✏️</button>}
                            <button className="btn btn-danger btn-sm btn-icon" onClick={()=>handleDelete(t._id||t.id)}>🗑</button>
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              )
          }
        </div>
      </div>
    </div>
  );
}

// ── INTERNS PAGE ──────────────────────────────────────────────────────────────
export function InternsPage() {
  const { user, isSenior } = useAuth();
  const [report,      setReport]      = useState([]);
  const [loading,     setLoading]     = useState(true);
  const [toast,       setToast]       = useState(null);
  const [resetTarget, setResetTarget] = useState(null);
  const [newPass,     setNewPass]     = useState("");
  const [resetting,   setResetting]   = useState(false);

  useEffect(() => {
    reportAPI.interns()
      .then(d => { setReport(d.report||[]); setLoading(false); })
      .catch(()=>setLoading(false));
  }, []);

  const handleResetPassword = async () => {
    if (!newPass || newPass.length < 6) { setToast({ msg:"Password must be at least 6 characters.", type:"error" }); return; }
    setResetting(true);
    try {
      await authAPI.resetPassword(resetTarget._id, { newPassword: newPass });
      setToast({ msg:`Password reset for ${resetTarget.name}.`, type:"success" });
      setResetTarget(null); setNewPass("");
    } catch(e) { setToast({ msg:e.message, type:"error" }); }
    setResetting(false);
  };

  if (loading) return <div style={{ padding:60, textAlign:"center" }}><div className="spinner"/></div>;

  return (
    <div className="animate-fadeUp">
      {toast && <Toast message={toast.msg} type={toast.type} onClose={() => setToast(null)}/>}

      {resetTarget && (
        <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.55)", display:"flex", alignItems:"center", justifyContent:"center", zIndex:200, padding:16 }}
          onClick={e => e.target===e.currentTarget && setResetTarget(null)}>
          <div style={{ background:"white", borderRadius:18, width:380, padding:"32px 28px", boxShadow:"0 24px 80px rgba(0,0,0,.3)" }}>
            <div style={{ fontFamily:"Syne,sans-serif", fontWeight:800, fontSize:18, color:"#0a2e1a", marginBottom:6 }}>🔑 Reset Password</div>
            <p style={{ fontSize:13, color:"#6b7280", marginBottom:20 }}>Set a new temporary password for <strong>{resetTarget.name}</strong>.</p>
            <label style={{ fontSize:12, fontWeight:600, color:"#374151", display:"block", marginBottom:5 }}>New Password</label>
            <input type="password" className="form-input" style={{ marginBottom:20 }} value={newPass} onChange={e=>setNewPass(e.target.value)} placeholder="Min. 6 characters" onKeyDown={e=>e.key==="Enter"&&handleResetPassword()}/>
            <div style={{ display:"flex", gap:10, justifyContent:"flex-end" }}>
              <button className="btn btn-secondary" onClick={()=>{setResetTarget(null);setNewPass("");}}>Cancel</button>
              <button className="btn btn-primary" onClick={handleResetPassword} disabled={resetting}>{resetting?"Resetting…":"Reset Password"}</button>
            </div>
          </div>
        </div>
      )}

      <div className="grid-3">
        {report.map(intern => (
          <div key={intern._id} className="intern-card">
            <div className="flex items-center gap-12 mb-16">
              <Avatar initials={intern.avatar} color={intern.avatarColor} size="lg"/>
              <div>
                <div style={{ fontFamily:"Syne,sans-serif", fontWeight:800, fontSize:15, color:"var(--green-900)" }}>{intern.name}</div>
                <div style={{ fontSize:12, color:"var(--green-600)", fontWeight:600, marginTop:2 }}>{intern.position}</div>
              </div>
            </div>
            <div style={{ fontSize:12, color:"var(--gray-500)", marginBottom:14, lineHeight:1.8 }}>📅 {intern.startDate} → {intern.endDate}</div>
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr 1fr", gap:8, marginBottom:14, textAlign:"center" }}>
              {[["Tasks",intern.stats.total],["Done",intern.stats.done],["Hours",formatMinutes(intern.stats.totalMins)]].map(([l,v]) => (
                <div key={l} style={{ background:"var(--green-50)", borderRadius:8, padding:"8px 4px" }}>
                  <div style={{ fontFamily:"Syne,sans-serif", fontWeight:800, fontSize:16, color:"var(--green-900)" }}>{v}</div>
                  <div style={{ fontSize:10, color:"var(--gray-400)", fontWeight:600, textTransform:"uppercase", letterSpacing:".5px", marginTop:2 }}>{l}</div>
                </div>
              ))}
            </div>
            {intern.stats.leaveDays > 0 && (
              <div style={{ background:"#fffbeb", border:"1px solid #fde68a", borderRadius:8, padding:"7px 12px", marginBottom:12, fontSize:12, color:"#92400e", fontWeight:600 }}>
                🏖️ {intern.stats.leaveDays} leave day{intern.stats.leaveDays>1?"s":""} this period
              </div>
            )}
            <div className="flex justify-between mb-8">
              <span className="text-xs text-gray">Completion</span>
              <span style={{ fontSize:12, fontWeight:700, color:intern.stats.pct>70?"var(--green-500)":"var(--orange)" }}>{intern.stats.pct}%</span>
            </div>
            <div className="progress-bar mb-12">
              <div className={`progress-fill${intern.stats.pct<50?" warn":""}`} style={{ width:intern.stats.pct+"%" }}/>
            </div>
            <div className="flex justify-between mb-6">
              <span className="text-xs text-gray">⏱ Weekly hours</span>
              <span style={{ fontSize:11, fontWeight:700, color:intern.stats.weekPct>=100?"#16a34a":intern.stats.weekPct>=60?"#1d4ed8":"#d97706" }}>
                {formatMinutes(intern.stats.weekMins||0)} / 30h
              </span>
            </div>
            <WeeklyHoursBar weekMins={intern.stats.weekMins||0} compact/>
            <button
              onClick={() => setResetTarget({ _id: intern._id, name: intern.name })}
              style={{ marginTop:14, width:"100%", padding:"7px", borderRadius:8, border:"1px solid #fecaca", background:"#fef2f2", color:"#dc2626", fontSize:12, fontWeight:600, cursor:"pointer", fontFamily:"inherit" }}
            >
              🔑 Reset Password
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}

// ── PROJECTS PAGE ─────────────────────────────────────────────────────────────
export function ProjectsPage() {
  const [report,  setReport]  = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    reportAPI.projects()
      .then(d => { setReport(d.report||[]); setLoading(false); })
      .catch(()=>setLoading(false));
  }, []);

  if (loading) return <div style={{ padding:60, textAlign:"center" }}><div className="spinner"/></div>;

  const lighten = hex => ({"#1a6640":"#2ecc7a","#2563eb":"#60a5fa","#16a34a":"#4ade80"})[hex]||"#2ecc7a";

  return (
    <div className="animate-fadeUp">
      <div className="grid-3 mb-24">
        {report.map(p => (
          <div key={p._id||p.id} className="card">
            <div className="card-body">
              <div className="flex items-center gap-12 mb-18">
                <div style={{ width:48, height:48, borderRadius:14, background:`linear-gradient(135deg,${p.color},${lighten(p.color)})`, display:"flex", alignItems:"center", justifyContent:"center", fontSize:22, flexShrink:0 }}>{p.icon}</div>
                <div>
                  <div style={{ fontFamily:"Syne,sans-serif", fontWeight:800, fontSize:18, color:"var(--green-900)" }}>{p.name}</div>
                  <div style={{ fontSize:12, color:"var(--gray-500)" }}>{p.fullName}</div>
                </div>
              </div>
              {[["Total Tasks",p.stats.total],["Completed",p.stats.done],["Hours",formatMinutes(p.stats.totalMins)],["In Progress",p.stats.inProgress||0]].map(([l,v]) => (
                <div key={l} style={{ display:"flex", justifyContent:"space-between", padding:"9px 0", borderBottom:"1px solid var(--gray-100)", fontSize:13 }}>
                  <span className="text-gray">{l}</span><span style={{ fontWeight:700 }}>{v}</span>
                </div>
              ))}
              <div style={{ marginTop:14 }}>
                <div className="flex justify-between mb-8"><span className="text-xs text-gray">Progress</span><span style={{ fontSize:13, fontWeight:700, color:"var(--green-600)" }}>{p.stats.pct}%</span></div>
                <div className="progress-bar" style={{ height:9 }}>
                  <div className={`progress-fill${p.stats.pct<40?" danger":p.stats.pct<70?" warn":""}`} style={{ width:p.stats.pct+"%" }}/>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
